/// <summary>
/// Extension of the <c>SalesAgreementCreate</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formStr(SalesAgreementCreate))]
final class SalesAgreementCreateETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>canClose</c> method.
/// </summary>
/// <returns>
/// Returns a boolean value indicating whether the form can close.
/// </returns>
boolean canClose()
{
    boolean ret = next canClose();

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (this.closedOk())
        {
            this.ETGSPAINcreateAgreementLineFromETGSPAINOperation();
        }
    }

    return ret;
}

/// <summary>
/// Method for creating agreement lines from operations.
/// </summary>
public void ETGSPAINcreateAgreementLineFromETGSPAINOperation()
{
    ETGSPAINPurchOperationTable  ETGSPAINPurchOperationTable;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (SalesAgreementHeader.ETGSPAINAgreementOperationId)
        {
            ETGSPAINPurchOperationTable = ETGSPAINPurchOperationTable::find(SalesAgreementHeader.ETGSPAINAgreementOperationId);

            if (ETGSPAINPurchOperationTable)
            {
                AgreementLineQuantityCommitment::createAgreementLineFromETGSPAINOperation(ETGSPAINPurchOperationTable, SalesAgreementHeader);
            }
        }
    }
}

/// <summary>
/// Lookup method for the <c>SalesAgreementHeader_ETGSPAINSalesAgreementOperationId</c> control in the <c>SalesAgreementCreate</c> form.
/// </summary>
/// <param name="_sender">FormControl.</param>
/// <param name="_e">FormControlEventArgs.</param>
[FormControlEventHandler(formControlStr(SalesAgreementCreate, SalesAgreementHeader_ETGSPAINAgreementOperationId), FormControlEventType::Lookup)]
public static void SalesAgreementHeader_ETGSPAINPurchAgreementOperationId_OnLookup(FormControl _sender, FormControlEventArgs _e)
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        ETGSPAINPurchOperationTable::OperationIdBatchIdLookUp(tableNum(SalesAgreementHeader), _sender, _e);
    }
}

/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>This code is used to show or hide features in Spanish companies.</remarks>
public void init()
{
    next init();

    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    if (currentCompanyIsSpanishCompany)
    {
        FormRun formRun                         = this as FormRun;

        SalesAgreementHeader::ETGSPAINmandatoryOperationFields(formRun);
    }

    this.design().controlName(formControlStr(SalesAgreementCreate, SalesAgreementHeader_ETGSPAINPurchCountryRegionIdOrigin)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementCreate, SalesAgreementHeader_ETGSPAINAgreementOperationId)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreementCreate, ETGSPAINAgreementHeaderDefault_DeliveryTerm)).visible(currentCompanyIsSpanishCompany);
    AgreementHeaderDefault_DS.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).mandatory(currentCompanyIsSpanishCompany);
}
